import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { API } from '@/App';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { toast } from 'sonner';
import { ArrowLeft, Plus, Edit, Trash2, Store, Menu as MenuIcon, ShoppingBag } from 'lucide-react';

const AdminDashboard = ({ user }) => {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('restaurants');
  const [restaurants, setRestaurants] = useState([]);
  const [menuItems, setMenuItems] = useState([]);
  const [orders, setOrders] = useState([]);
  const [showRestaurantModal, setShowRestaurantModal] = useState(false);
  const [showMenuModal, setShowMenuModal] = useState(false);
  const [editingRestaurant, setEditingRestaurant] = useState(null);
  const [editingMenuItem, setEditingMenuItem] = useState(null);

  const token = localStorage.getItem("token");

  const authHeader = {
    headers: {
      Authorization: `Bearer ${token}`
    }
  };

  const [restaurantForm, setRestaurantForm] = useState({
    name: '',
    description: '',
    image: '',
    cuisine_type: '',
    rating: 4.0,
    delivery_time: '30-40 min'
  });

  const [menuForm, setMenuForm] = useState({
    restaurant_id: '',
    name: '',
    description: '',
    price: 0,
    image: '',
    category: '',
    is_available: true
  });

  useEffect(() => {
    fetchData();
  }, [activeTab]);

  const fetchData = async () => {
    try {
      if (activeTab === 'restaurants') {
        const res = await axios.get(`${API}/restaurants`);
        setRestaurants(res.data);
      } 
      else if (activeTab === 'menu') {
        const restaurantsRes = await axios.get(`${API}/restaurants`);
        setRestaurants(restaurantsRes.data);

        const menuRequests = restaurantsRes.data.map(r =>
          axios.get(`${API}/restaurants/${r.id}/menu`)
        );

        const menuRes = await Promise.all(menuRequests);
        setMenuItems(menuRes.flatMap(r => r.data));
      } 
      else if (activeTab === 'orders') {
        const res = await axios.get(`${API}/orders`, authHeader);
        setOrders(res.data);
      }
    } catch (error) {
      console.error('Error fetching data:', error);
      toast.error("Failed to load admin data");
    }
  };

  // Restaurant CRUD
  const handleRestaurantSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editingRestaurant) {
        await axios.put(
          `${API}/restaurants/${editingRestaurant.id}`,
          restaurantForm,
          authHeader
        );
        toast.success('Restaurant updated successfully');
      } else {
        await axios.post(
          `${API}/restaurants`,
          restaurantForm,
          authHeader
        );
        toast.success('Restaurant created successfully');
      }
      setShowRestaurantModal(false);
      resetRestaurantForm();
      fetchData();
    } catch (error) {
      toast.error(error.response?.data?.detail || 'Operation failed');
    }
  };

  const handleDeleteRestaurant = async (id) => {
    if (!window.confirm('Are you sure? This will also delete all menu items.')) return;
    try {
      await axios.delete(`${API}/restaurants/${id}`, authHeader);
      toast.success('Restaurant deleted');
      fetchData();
    } catch (error) {
      toast.error('Failed to delete restaurant');
    }
  };

  const resetRestaurantForm = () => {
    setRestaurantForm({
      name: '',
      description: '',
      image: '',
      cuisine_type: '',
      rating: 4.0,
      delivery_time: '30-40 min'
    });
    setEditingRestaurant(null);
  };

  // Menu CRUD
  const handleMenuSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editingMenuItem) {
        await axios.put(
          `${API}/menu-items/${editingMenuItem.id}`,
          menuForm,
          authHeader
        );
        toast.success('Menu item updated successfully');
      } else {
        await axios.post(
          `${API}/menu-items`,
          menuForm,
          authHeader
        );
        toast.success('Menu item created successfully');
      }
      setShowMenuModal(false);
      resetMenuForm();
      fetchData();
    } catch (error) {
      toast.error(error.response?.data?.detail || 'Operation failed');
    }
  };

  const handleDeleteMenuItem = async (id) => {
    if (!window.confirm('Are you sure?')) return;
    try {
      await axios.delete(`${API}/menu-items/${id}`, authHeader);
      toast.success('Menu item deleted');
      fetchData();
    } catch (error) {
      toast.error('Failed to delete menu item');
    }
  };

  const resetMenuForm = () => {
    setMenuForm({
      restaurant_id: '',
      name: '',
      description: '',
      price: 0,
      image: '',
      category: '',
      is_available: true
    });
    setEditingMenuItem(null);
  };

  // Order status update
  const handleStatusUpdate = async (orderId, newStatus) => {
    try {
      await axios.put(
        `${API}/orders/${orderId}/status`,
        { status: newStatus },
        authHeader
      );
      toast.success('Order status updated');
      fetchData();
    } catch (error) {
      toast.error('Failed to update status');
    }
  };

  return (
    /* 🔴 UI BELOW IS 100% UNCHANGED 🔴 */
    <div className="min-h-screen bg-gradient-to-br from-[#FFF5EE] to-[#FFE4E1]">
      {/* entire JSX exactly same as your original */}
    </div>
  );
};

export default AdminDashboard;
